import{_ as t,o as a,c as r,a3 as i}from"./chunks/framework.LBeL10WQ.js";const u=JSON.parse('{"title":"1. Advertiser Brief","description":"","frontmatter":{"title":"1. Advertiser Brief"},"headers":[],"relativePath":"en/advertisers/dedicated-email/1-brief-annonceur.md","filePath":"en/advertisers/dedicated-email/1-brief-annonceur.md"}'),o={name:"en/advertisers/dedicated-email/1-brief-annonceur.md"};function s(n,e,d,l,h,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="step-1-the-advertiser-brief" tabindex="-1">Step 1: The Advertiser Brief <a class="header-anchor" href="#step-1-the-advertiser-brief" aria-label="Permalink to &quot;Step 1: The Advertiser Brief&quot;">​</a></h1><p>Your role: provide the &quot;raw material&quot; that will allow the distributor to build a high-performing email.</p><hr><h2 id="fill-out-the-form" tabindex="-1">Fill out the form <a class="header-anchor" href="#fill-out-the-form" aria-label="Permalink to &quot;Fill out the form&quot;">​</a></h2><p>Every campaign starts with submitting the brief via our dedicated form.</p><p>→ <strong><a href="https://tally.so/r/9qN9WY" target="_blank">Access the Brief form (Tally)</a></strong></p><hr><h2 id="what-you-need-to-provide" tabindex="-1">What you need to provide <a class="header-anchor" href="#what-you-need-to-provide" aria-label="Permalink to &quot;What you need to provide&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>🎁 The Offer</strong><p>What is the promise? Be clear and incentive. Example: <em>&quot;20€ off for orders over 100€&quot;</em>.</p><p>Specify the validity period (recommended minimum: 3 months).</p></div><div class="gi-value-card"><strong>🖼️ The Visuals</strong><p>Vector or HD logo, product packshots on a white background, lifestyle visuals if available.</p></div><div class="gi-value-card"><strong>✍️ The Wording</strong><p>Key arguments (USPs), brand tone, mandatory keywords to include in the email text.</p></div><div class="gi-value-card"><strong>🔗 The Links</strong><p>Destination URLs (landing pages) to direct traffic to. These links are dynamic — editable at any time.</p></div></div><div class="tip custom-block"><p class="custom-block-title">Advice: let the distributor adapt</p><p>Do not try to impose strict brand guidelines. The distributor knows their community — let them adapt your visuals to their universe to maximize engagement.</p><p><strong>The goal is a recommendation, not an ad.</strong> A 100% branded email without mentioning the partner increases unsubscribes and drops performance.</p></div><hr><h2 id="what-s-next" tabindex="-1">What&#39;s next? <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next?&quot;">​</a></h2><p>Once the brief is sent, the getinside team sets up the campaign and notifies the distributor to start creation.</p><p>→ Next step: <a href="./2-creation-distributeur.html">Production &amp; Co-branding</a></p>',14)])])}const m=t(o,[["render",s]]);export{u as __pageData,m as default};
